def generateParentheses(data):
    text = (data or "").strip()
    if not text:
        return ""
    n = int(text)
    out = []

    def backtrack(cur, open_n, close_n):
        if len(cur) == 2 * n:
            out.append(cur)
            return
        if open_n < n:
            backtrack(cur + "(", open_n + 1, close_n)
        if close_n < open_n:
            backtrack(cur + ")", open_n, close_n + 1)

    backtrack("", 0, 0)
    return "\n".join(out)

